const ExpensiveList = React.memo(function ExpensiveList({ items, onItemClick }) {
  // Renders thousands of items; re-render is expensive.
  return (
    <ul>
      {items.map(item => (
        <li key={item.id} onClick={() => onItemClick(item.id)}>{item.name}</li>
      ))}
    </ul>
  );
});

function Parent({ items }) {
  const [selectedId, setSelectedId] = useState(null);
  // useCallback here because ExpensiveList is memoized and we measured
  // the re-render cost to be significant (>16ms in profiler).
  const handleItemClick = useCallback((id) => setSelectedId(id), []);

  return <ExpensiveList items={items} onItemClick={handleItemClick} />;
}
